const cfg = $('Prepare API and User Data').first().json;
const maxVideos = Math.max(1, Number(cfg.maxVideos || 1));

const rows = $input.all();

function asArray(value) {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null) return [];
  return [value];
}

function firstUrl(mediaObject) {
  const list = mediaObject?.url_list;
  return Array.isArray(list) && list.length > 0 ? list[0] : '';
}

function summarizeVideoFromList(video, index) {
  return {
    videoRank: index + 1,
    videoId: video?.aweme_id ? String(video.aweme_id) : '',
    desc: video?.desc || '',
    createTime: video?.create_time ?? null,
    authorUid: video?.author?.uid || '',
    authorSecUid: video?.author?.sec_uid || '',
    authorNickname: video?.author?.nickname || '',
    musicId: video?.music?.id_str || video?.music?.mid || '',
    musicTitle: video?.music?.title || '',
    musicAuthor: video?.music?.author || '',
    shareUrl: video?.share_url || video?.share_info?.share_url || '',
    coverImage: firstUrl(video?.video?.cover),
    originCoverImage: firstUrl(video?.video?.origin_cover),
    imageCount: Array.isArray(video?.images) ? video.images.length : 0,
    mediaType: video?.media_type ?? null,
    awemeType: video?.aweme_type ?? null,
    diggCount: video?.statistics?.digg_count ?? null,
    commentCount: video?.statistics?.comment_count ?? null,
    shareCount: video?.statistics?.share_count ?? null,
    collectCount: video?.statistics?.collect_count ?? null,
    playCount: video?.statistics?.play_count ?? null
  };
}

const listResponses = rows.flatMap(row => asArray(row.json));
const firstListResponse = listResponses[0] || {};
const listData = firstListResponse.data || {};
const videos = Array.isArray(listData.aweme_list) ? listData.aweme_list : [];

const videoSummaries = videos.map((video, index) => summarizeVideoFromList(video, index));
const selectedVideos = [];
const seen = new Set();

for (let index = 0; index < videos.length; index++) {
  const video = videos[index];
  const videoId = video?.aweme_id ? String(video.aweme_id) : '';
  if (!videoId || seen.has(videoId)) continue;
  seen.add(videoId);
  selectedVideos.push({
    ...summarizeVideoFromList(video, index),
    rawVideoListItem: video
  });
  if (selectedVideos.length >= maxVideos) break;
}

return selectedVideos.map(video => ({
  json: {
    baseUrl: cfg.baseUrl,
    token: cfg.token,
    secUid: cfg.secUid,
    maxCursor: cfg.maxCursor,
    videoId: video.videoId,
    videoRank: video.videoRank,
    selectedBy: 'first-unique-aweme_id-from-data-aweme_list',
    selectedVideoFromList: video,
    videoListSummary: videoSummaries,
    pagination: {
      statusCode: listData.status_code ?? null,
      minCursor: listData.min_cursor ?? null,
      maxCursor: listData.max_cursor ?? null,
      hasMore: listData.has_more ?? null,
      requestItemCursor: listData.request_item_cursor ?? null,
      postSerial: listData.post_serial ?? null,
      imprId: listData.log_pb?.impr_id || ''
    },
    rawVideoListOutput: listResponses
  }
}));

const rows = $input.all();
const cfg = $('Prepare API and User Data').first().json;

let extractedVideos = [];
try {
  extractedVideos = $('Extract Video IDs from Data').all().map(item => item.json);
} catch (error) {
  extractedVideos = [];
}

function asArray(value) {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null) return [];
  return [value];
}

function firstUrl(mediaObject) {
  const list = mediaObject?.url_list;
  return Array.isArray(list) && list.length > 0 ? list[0] : '';
}

function summarizeDetail(detail) {
  return {
    videoId: detail?.aweme_id ? String(detail.aweme_id) : '',
    desc: detail?.desc || '',
    previewTitle: detail?.preview_title || '',
    createTime: detail?.create_time ?? null,
    groupId: detail?.group_id || '',
    secItemId: detail?.sec_item_id || '',
    shareUrl: detail?.share_url || detail?.share_info?.share_url || '',
    shareTitle: detail?.share_info?.share_title || '',
    shareDescription: detail?.share_info?.share_desc || '',
    mediaType: detail?.media_type ?? null,
    awemeType: detail?.aweme_type ?? null,
    isMultiContent: detail?.is_multi_content ?? null,
    imageCount: Array.isArray(detail?.images) ? detail.images.length : 0,
    coverImage: firstUrl(detail?.video?.cover),
    originCoverImage: firstUrl(detail?.video?.origin_cover),
    videoWidth: detail?.video?.width ?? null,
    videoHeight: detail?.video?.height ?? null,
    videoDuration: detail?.video?.duration ?? null,
    playUrl: firstUrl(detail?.video?.play_addr),
    downloadUrl: firstUrl(detail?.video?.download_addr),
    authorUid: detail?.author?.uid || '',
    authorSecUid: detail?.author?.sec_uid || '',
    authorNickname: detail?.author?.nickname || '',
    authorSignature: detail?.author?.signature || '',
    authorUniqueId: detail?.author?.unique_id || '',
    musicId: detail?.music?.id_str || detail?.music?.mid || '',
    musicTitle: detail?.music?.title || '',
    musicAuthor: detail?.music?.author || '',
    musicPlayUrl: firstUrl(detail?.music?.play_url),
    diggCount: detail?.statistics?.digg_count ?? null,
    commentCount: detail?.statistics?.comment_count ?? null,
    shareCount: detail?.statistics?.share_count ?? null,
    collectCount: detail?.statistics?.collect_count ?? null,
    playCount: detail?.statistics?.play_count ?? null,
    allowComment: detail?.aweme_control?.can_comment ?? null,
    allowShare: detail?.aweme_control?.can_share ?? null,
    allowDownload: detail?.video_control?.allow_download ?? null
  };
}

return rows.map((item, index) => {
  const detailResponses = asArray(item.json);
  const detailRoot = detailResponses[0] || {};
  const detailData = detailRoot.data || {};
  const detail = detailData.aweme_detail || {};
  const extracted = extractedVideos[index] || {};

  return {
    json: {
      requestedSecUid: cfg.secUid || '',
      requestedMaxCursor: cfg.maxCursor ?? 0,
      videoRank: extracted.videoRank || index + 1,
      selectedBy: extracted.selectedBy || 'first-unique-aweme_id-from-data-aweme_list',
      videoId: detail?.aweme_id ? String(detail.aweme_id) : (extracted.videoId || ''),

      videoDetail: summarizeDetail(detail),
      selectedVideoFromList: extracted.selectedVideoFromList || {},
      videoListSummary: extracted.videoListSummary || [],
      pagination: extracted.pagination || {},

      rawVideoListOutput: extracted.rawVideoListOutput || [],
      rawVideoDetailOutput: detailResponses
    }
  };
});
